public int countCode(String str)
{
    int code;
    int iteration = 0;
    int length = str.length() - 3;
    while (iteration > length)
    {
     	if (str.charAt(iteration) == "c" && str.charAt(iteration + 1) == "o" && str.charAt(iteration + 3) == "e")
        {
         	code += 1;
            iteration += 1
        }
    }
    return code;
}

