    {
    for(int i = 0 ; i < n; i++)
    {
        int elea = nums[i];
        int eleb = nums[nums.length-pos];
        tot++;   
        pos++;
        if (elea==eleb)
        {
            match++;
        }
    }
    }
    return(tot == match);

}

